import{_ as s,c as n,o as a,d as l}from"./app.6a29fc53.js";const h=JSON.parse('{"title":"Vagrant与VirtualBox搭建虚拟机","description":"vagrant、virtual box","frontmatter":{"title":"Vagrant与VirtualBox搭建虚拟机","description":"vagrant、virtual box","date":"2022-08-22T00:00:00.000Z","category":"虚拟机","tags":["vagrant","virtual box"]},"headers":[{"level":2,"title":"Vagrant","slug":"vagrant","link":"#vagrant","children":[]},{"level":2,"title":"VirtualBox","slug":"virtualbox","link":"#virtualbox","children":[]},{"level":2,"title":"Vagrant Box","slug":"vagrant-box","link":"#vagrant-box","children":[]},{"level":2,"title":"创建虚拟机","slug":"创建虚拟机","link":"#创建虚拟机","children":[]},{"level":2,"title":"远程控制","slug":"远程控制","link":"#远程控制","children":[]},{"level":2,"title":"安装开发环境","slug":"安装开发环境","link":"#安装开发环境","children":[]},{"level":2,"title":"参考","slug":"参考","link":"#参考","children":[]}],"relativePath":"posts/vagrant虚拟机.md","lastUpdated":1670912864000}'),e={name:"posts/vagrant虚拟机.md"},p=l(`<h1 id="vagrant与virtualbox搭建虚拟机" tabindex="-1">Vagrant与VirtualBox搭建虚拟机 <a class="header-anchor" href="#vagrant与virtualbox搭建虚拟机" aria-hidden="true">#</a></h1><h2 id="vagrant" tabindex="-1">Vagrant <a class="header-anchor" href="#vagrant" aria-hidden="true">#</a></h2><p>下载地址：<a href="https://www.vagrantup.com/downloads" target="_blank" rel="noreferrer">https://www.vagrantup.com/downloads</a></p><h2 id="virtualbox" tabindex="-1">VirtualBox <a class="header-anchor" href="#virtualbox" aria-hidden="true">#</a></h2><p>下载地址：<a href="https://www.virtualbox.org/wiki/Downloads" target="_blank" rel="noreferrer">https://www.virtualbox.org/wiki/Downloads</a></p><p>配置虚拟机默认安装地址</p><p>打开全局设置，配置虚拟机安装地址</p><h2 id="vagrant-box" tabindex="-1">Vagrant Box <a class="header-anchor" href="#vagrant-box" aria-hidden="true">#</a></h2><p>Vagrant Box下载地址：<a href="https://app.vagrantup.com/boxes/search" target="_blank" rel="noreferrer">https://app.vagrantup.com/boxes/search</a></p><p>下载完后，打开命令窗口，将它添加到Vagrant管理的box列表中</p><div class="language-shell line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki"><code><span class="line"><span style="color:#676E95;"># centos7 是box名字 后面是路径</span></span>
<span class="line"><span style="color:#A6ACCD;">vagrant box add centos7 e:\\xx\\xx.box</span></span>
<span class="line"></span>
<span class="line"><span style="color:#676E95;"># 查看是否添加成功</span></span>
<span class="line"><span style="color:#A6ACCD;">vagrant box list</span></span>
<span class="line"></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><h2 id="创建虚拟机" tabindex="-1">创建虚拟机 <a class="header-anchor" href="#创建虚拟机" aria-hidden="true">#</a></h2><p>创建一个文件夹统一管理vagrantfile，如：<code>e:/vm/vagrantfile/centos7</code></p><div class="language-shell line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki"><code><span class="line"><span style="color:#676E95;"># 到e:/vm/vagrantfile/centos7路径下 centos7是上面add的box名称</span></span>
<span class="line"><span style="color:#A6ACCD;">vagrant init centos7</span></span>
<span class="line"></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><blockquote><p>执行完得到一个vagrantfile文件，可以配置虚拟机相关信息</p></blockquote><p>常用命令</p><div class="language-shell line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki"><code><span class="line"><span style="color:#676E95;"># 启动虚拟机</span></span>
<span class="line"><span style="color:#A6ACCD;">vagrant up</span></span>
<span class="line"><span style="color:#676E95;"># 关机</span></span>
<span class="line"><span style="color:#A6ACCD;">vagrant halt</span></span>
<span class="line"></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><h2 id="远程控制" tabindex="-1">远程控制 <a class="header-anchor" href="#远程控制" aria-hidden="true">#</a></h2><div class="language-shell line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki"><code><span class="line"><span style="color:#676E95;"># 虚拟机启动后先使用默认账号登录</span></span>
<span class="line"><span style="color:#A6ACCD;">vagrant ssh</span></span>
<span class="line"><span style="color:#676E95;"># 修改root用户密码</span></span>
<span class="line"><span style="color:#A6ACCD;">sudo passwd root</span></span>
<span class="line"><span style="color:#676E95;"># 修改 /etc/ssh/sshd_config </span></span>
<span class="line"><span style="color:#A6ACCD;">vi /etc/ssh/sshd_config</span></span>
<span class="line"></span>
<span class="line"><span style="color:#676E95;"># 放开以下的注释</span></span>
<span class="line"><span style="color:#A6ACCD;">37 LoginGraceTime 2m</span></span>
<span class="line"><span style="color:#A6ACCD;">38 PermitRootLogin yes</span></span>
<span class="line"><span style="color:#A6ACCD;">39 StrictModes yes</span></span>
<span class="line"></span>
<span class="line"><span style="color:#A6ACCD;">62 </span><span style="color:#676E95;"># To disable tunneled clear text passwords, change to no here!</span></span>
<span class="line"><span style="color:#A6ACCD;">63 PasswordAuthentication yes</span></span>
<span class="line"><span style="color:#A6ACCD;">64 </span><span style="color:#676E95;">#PermitEmptyPasswords no</span></span>
<span class="line"><span style="color:#A6ACCD;">65 </span><span style="color:#676E95;">#PasswordAuthentication no</span></span>
<span class="line"></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br></div></div><p>修改完配置重启</p><div class="language-shell line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki"><code><span class="line"><span style="color:#A6ACCD;">service sshd restart</span></span>
<span class="line"></span>
<span class="line"><span style="color:#676E95;"># 重启</span></span>
<span class="line"><span style="color:#A6ACCD;">vagrant reload</span></span>
<span class="line"></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>使用ssh连接</p><h2 id="安装开发环境" tabindex="-1">安装开发环境 <a class="header-anchor" href="#安装开发环境" aria-hidden="true">#</a></h2><p>先安装基本工具</p><div class="language-shell line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki"><code><span class="line"><span style="color:#A6ACCD;">yum -y install nano vim wget curl net-tools lsof zip unzip</span></span>
<span class="line"></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>换源</p><ol><li><p>备份旧的源</p><div class="language-shell line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki"><code><span class="line"><span style="color:#A6ACCD;">mv /etc/yum.repos.d/CentOS-Base.repo /etc/yum.repos.d/CentOS-Base.repo.backup</span></span>
<span class="line"></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></li><li><p>下载对应版本的阿里源（wget -O 下载并以指定的文件名保存）</p><div class="language-shell line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki"><code><span class="line"><span style="color:#A6ACCD;">wget -O /etc/yum.repos.d/CentOS-Base.repo https://mirrors.aliyun.com/repo/Centos-8.repo</span></span>
<span class="line"></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></li><li><p>删除yum旧的缓存，生成新的换源后的缓存</p><div class="language-shell line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki"><code><span class="line"><span style="color:#A6ACCD;">// 清理源缓存</span></span>
<span class="line"><span style="color:#A6ACCD;">yum clean all </span><span style="color:#89DDFF;">&amp;&amp;</span><span style="color:#A6ACCD;"> yum makecache</span></span>
<span class="line"><span style="color:#A6ACCD;">// 更新源</span></span>
<span class="line"><span style="color:#A6ACCD;">yum -y update</span></span>
<span class="line"></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div></li></ol><p>静态ip</p><div class="language-shell line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki"><code><span class="line"><span style="color:#A6ACCD;">ip addr</span></span>
<span class="line"></span>
<span class="line"><span style="color:#82AAFF;">cd</span><span style="color:#A6ACCD;"> /etc/sysconfig/network-scripts/</span></span>
<span class="line"><span style="color:#A6ACCD;">ls ifcfig</span><span style="color:#89DDFF;">*</span></span>
<span class="line"></span>
<span class="line"><span style="color:#A6ACCD;">vim ifcfig</span></span>
<span class="line"></span>
<span class="line"><span style="color:#A6ACCD;">BOOTPROTO=“static” </span><span style="color:#676E95;">#dhcp改为static</span></span>
<span class="line"><span style="color:#A6ACCD;">ONBOOT=“yes” </span><span style="color:#676E95;">#开机启用本配置</span></span>
<span class="line"><span style="color:#A6ACCD;">IPADDR=192.168.244.101 </span><span style="color:#676E95;">#静态IP</span></span>
<span class="line"><span style="color:#A6ACCD;">GATEWAY=192.168.244.2 </span><span style="color:#676E95;">#默认网关</span></span>
<span class="line"><span style="color:#A6ACCD;">NETMASK=255.255.255.0 </span><span style="color:#676E95;">#子网掩码</span></span>
<span class="line"><span style="color:#A6ACCD;">DNS1=192.168.244.2 </span><span style="color:#676E95;">#DNS 配置</span></span>
<span class="line"></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br></div></div><div class="language-shell line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki"><code><span class="line"><span style="color:#676E95;"># 下载编译环境</span></span>
<span class="line"><span style="color:#A6ACCD;">yum install -y gcc-c++   pcre pcre-devel zlib zlib-devel openssl openssl-devel</span></span>
<span class="line"><span style="color:#676E95;"># 下载安装包</span></span>
<span class="line"><span style="color:#A6ACCD;">wget -c https://nginx.org/download/nginx-1.18.0.tar.gz</span></span>
<span class="line"><span style="color:#676E95;"># 解压</span></span>
<span class="line"><span style="color:#A6ACCD;">tar -zxvf nginx-1.18.0.tar.gz</span></span>
<span class="line"><span style="color:#676E95;"># 进入目录</span></span>
<span class="line"><span style="color:#82AAFF;">cd</span><span style="color:#A6ACCD;"> nginx-1.18.0</span></span>
<span class="line"><span style="color:#676E95;"># 配置</span></span>
<span class="line"><span style="color:#A6ACCD;">./configure</span></span>
<span class="line"><span style="color:#676E95;"># 编译安装</span></span>
<span class="line"><span style="color:#A6ACCD;">make </span><span style="color:#89DDFF;">&amp;&amp;</span><span style="color:#A6ACCD;"> make install</span></span>
<span class="line"><span style="color:#676E95;"># 查看安装路径</span></span>
<span class="line"><span style="color:#A6ACCD;">whereis nginx</span></span>
<span class="line"><span style="color:#676E95;"># 开机启动</span></span>
<span class="line"><span style="color:#A6ACCD;">vi /etc/rc.local</span></span>
<span class="line"><span style="color:#676E95;"># 底部添加一行</span></span>
<span class="line"><span style="color:#A6ACCD;">/usr/local/nginx/sbin/nginx</span></span>
<span class="line"><span style="color:#676E95;"># 设置权限</span></span>
<span class="line"><span style="color:#A6ACCD;">chmod 755 /etc/rc.local</span></span>
<span class="line"></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br></div></div><h2 id="参考" tabindex="-1">参考 <a class="header-anchor" href="#参考" aria-hidden="true">#</a></h2><ul><li><a href="https://blog.csdn.net/qq_44713454/article/details/119943743" target="_blank" rel="noreferrer">Vagrant 与 VirtualBox 的保姆级安装教程</a></li><li><a href="https://blog.csdn.net/cbcxvbfxgb/article/details/106868092" target="_blank" rel="noreferrer">vagrant root账号登录</a></li></ul>`,32),r=[p];function c(i,o,t,b,d,u){return a(),n("div",null,r)}const y=s(e,[["render",c]]);export{h as __pageData,y as default};
